{"code":"import json
import pandas as pd

# Load data
with open(locals()['var_function-call-14308479026833020990'], 'r') as f:
    contracts = json.load(f)
with open(locals()['var_function-call-14308479026833022329'], 'r') as f:
    opportunities = json.load(f)
with open(locals()['var_function-call-14308479026833019572'], 'r') as f:
    line_items = json.load(f)
pricebook_entries = locals()['var_function-call-14308479026833020911']

# Helper to clean IDs
def clean_id(x):
    if not isinstance(x, str):
        return None
    return x.strip().lstrip('#')

# 1. Process Contracts
valid_contract_ids = set()
start_date = "2022-06-25"
end_date = "2022-11-25"

for c in contracts:
    d = c.get('CompanySignedDate')
    if d:
        d = d.strip()
        if start_date <= d <= end_date:
            cid = clean_id(c.get('Id'))
            if cid:
                valid_contract_ids.add(cid)

# 2. Process Opportunities
valid_ops = {} # Map OpId -> OwnerId
for op in opportunities:
    cid = clean_id(op.get('ContractID__c'))
    if cid and cid in valid_contract_ids:
        oid = clean_id(op.get('Id'))
        owner = clean_id(op.get('OwnerId'))
        if oid and owner:
            valid_ops[oid] = owner

# 3. Process PricebookEntries
pbe_map = {} # Id -> UnitPrice
for pbe in pricebook_entries:
    pid = clean_id(pbe.get('Id'))
    u_price = pbe.get('UnitPrice')
    if pid and u_price:
        try:
            pbe_map[pid] = float(u_price)
        except ValueError:
            pass

# 4. Process Line Items and Calculate Sales
agent_sales = {} # OwnerId -> Total Sales

for item in line_items:
    op_id = clean_id(item.get('OpportunityId'))
    if op_id and op_id in valid_ops:
        pbe_id = clean_id(item.get('PricebookEntryId'))
        qty_str = item.get('Quantity')

        if pbe_id and pbe_id in pbe_map and qty_str:
            try:
                qty = float(qty_str)
                price = pbe_map[pbe_id]
                amount = qty * price

                owner = valid_ops[op_id]
                agent_sales[owner] = agent_sales.get(owner, 0.0) + amount
            except ValueError:
                pass

# Find top agent
if not agent_sales:
    print("__RESULT__:")
    print(json.dumps("No sales found"))
else:
    top_agent = max(agent_sales, key=agent_sales.get)
    print("__RESULT__:")
    print(json.dumps(top_agent))
